import{_ as e,o as t,c as r,af as o}from"./chunks/framework.DuHE0XFB.js";const u=JSON.parse('{"title":"如何做好技术管理","description":"","frontmatter":{"title":"如何做好技术管理","date":"2019-06-12 19:18:55 +0800"},"headers":[],"relativePath":"posts/manage.md","filePath":"posts/manage.md","lastUpdated":1783570921000}'),l={name:"posts/manage.md"};function i(h,a,n,d,s,p){return t(),r("div",null,[...a[0]||(a[0]=[o('<p>好的技术管理者应该是一名情商高、会沟通并且懂业务的技术人员，如果再懂一点管理，就能够胜任大部分工作。</p><h2 id="情商高" tabindex="-1">情商高 <a class="header-anchor" href="#情商高" aria-label="Permalink to &quot;情商高&quot;">​</a></h2><p>要能够控制情绪和心态，遇事不抱怨，懂得在适当的时候和场景去夸奖和批评，争论事情时要注意对事不对人，更重要的是要能够做到换位思考，当两个人在争论一件事情时，很多时候是因为他们对这件事都不是太懂。</p><h2 id="会沟通" tabindex="-1">会沟通 <a class="header-anchor" href="#会沟通" aria-label="Permalink to &quot;会沟通&quot;">​</a></h2><p>沟通能力是每一个技术人员都需要具备的基本能力，技术管理者在这方面应该做得更好。在沟通环节中有两个问题很重要，聆听和表达，其中懂得聆听尤为重要，先让别人把话说完！另外还需要注意有些事情一定要当面沟通，这样效率高而且不容易造成双方误解。</p><h2 id="懂业务" tabindex="-1">懂业务 <a class="header-anchor" href="#懂业务" aria-label="Permalink to &quot;懂业务&quot;">​</a></h2><p>只有对业务具有较深入的了解才能综合技术和业务角度去思考问题并做出适合的架构设计。</p><h2 id="有技术" tabindex="-1">有技术 <a class="header-anchor" href="#有技术" aria-label="Permalink to &quot;有技术&quot;">​</a></h2><p>在技术方面要具有一定的判断力和技术视野，不需要对各种技术都很精通，但必须有所了解，要能够对技术在该领域的发展趋势和应用场景有所了解，做技术架构的设计要有足够的弹性，既能够保证当前开发效率，又能够对未来产品技术架构的演进留出扩展的余地，并且不要过度设计。除此之外还需要具有较强的解决问题能力，当团队遇到技术困难时能够站出来解决它，否则很难在技术团队中建立威信。</p><h2 id="会管理" tabindex="-1">会管理 <a class="header-anchor" href="#会管理" aria-label="Permalink to &quot;会管理&quot;">​</a></h2><h3 id="对事管理" tabindex="-1">对事管理 <a class="header-anchor" href="#对事管理" aria-label="Permalink to &quot;对事管理&quot;">​</a></h3><p>做事前要先明确工作目标和优先级，重要并且着急的事情要先做，重要但是不着急的其次，然后是着急不重要的，最后是不重要也不着急的，当项目时间非常紧时，要懂得适当降级，不要因为一些不重要的细节问题拖跨整个事情。</p><p>任务分配前要先了解每个任务以及团队每个成员的情况，包括能力、性格、当前工作排期等，然后才能够将任务分配给合适的人，分配工作时要讲清楚目标和标准，否则完成效果出了问题后要先反思是不是自己的问题，leader 要能够替下属承担责任，但是如果自己做的都没有问题，并且下属多次出现同样过错，就要看下是否是其态度出了问题</p><h3 id="对人管理" tabindex="-1">对人管理 <a class="header-anchor" href="#对人管理" aria-label="Permalink to &quot;对人管理&quot;">​</a></h3><p>对上要完成给予的任务，对下要帮助解决问题并协调资源，还要帮助下属成长和提升，对于技术管理者来说对下管理是否能做好更重要一些。</p><h4 id="对上要注意反馈" tabindex="-1">对上要注意反馈 <a class="header-anchor" href="#对上要注意反馈" aria-label="Permalink to &quot;对上要注意反馈&quot;">​</a></h4><p>对上要注意信息对等，及时反应问题，不要让领导啥也不知道，出了问题后让别人告诉领导后就晚了，多沟通、多了解整体方向，好及时调整和应对，并且该争取的资源要争取，该背的锅要自己背上，少解释，多想想怎么解决，同样的错误不要犯两次。对于还没有解决的问题，要反馈出解决问题大概需要的时间及目前状态，对于已经解决的问题，要反馈出现问题的原因以及怎么避免再次发生，并且预计该问题造成的影响范围，不要一味的甩锅。</p><h4 id="对下要注意授权和培养" tabindex="-1">对下要注意授权和培养 <a class="header-anchor" href="#对下要注意授权和培养" aria-label="Permalink to &quot;对下要注意授权和培养&quot;">​</a></h4><p>要注重对成员的培养，培养他们的学习能力，思考能力和解决问题的能力，同时要授权组员去做事情，而不是怕他们做不好就自己做了，但授权不是放任不管，而是要针对不同员工类型做不同管理动作，对于新人要有人带，对于有初级经验的人可以讲完再让他做，经验丰富的人他做的时候可以关注下，并给出建议和要求，同时关注工作成果并帮他完善，能力强积极性高的，可分配更重要的工作，并让他参与设计决策中来。</p><p>组员做的时候还要给予技术以及资源等方面的支持，并定期评估结果给予反馈，当任一环节出现 delay 时要想办法及时补救，避免积少成多造成项目进度失控。进度把控上需要时刻监督执行的效果，但不是靠天天问进度来了解，也不要完全不管不问，对不熟悉的团队要把重点放在人身上，对熟悉并靠谱的团队要把重点放在事上，当事情结束后对做的好的经予鼓励，做的不好的要指出错误，错误的指出要明确和及时，要对事不对人，批评要将话题定位在事情本身上，去强调这件事没做好，而不是对方为什么不好好做事。</p><p>PS：要保护成员不被部门间其他乱七八糟的事情干扰，团队气氛还是很重要的</p>',21)])])}const m=e(l,[["render",i]]);export{u as __pageData,m as default};
